sql:
SELECT DISTINCT t.company_name 
FROM tenders t 
WHERE CAST(REPLACE(trim(t.budget, '$'), ',', '') AS REAL) > (
    SELECT AVG(CAST(REPLACE(trim(budget, '$'), ',', '') AS REAL)) 
    FROM tenders
);

SELECT company_name 
FROM tenders 
WHERE opening_date > '2023-06-10';

SELECT users.username, comments.comment_text
FROM users
JOIN comments ON users.user_id = comments.user_id;

SELECT COUNT(DISTINCT company_name) AS "Number of Companies"
FROM tenders
WHERE sector = 'Solar' AND CAST(REPLACE(budget, ',', '') AS REAL) > 10000000;

SELECT SUM(budget) AS total_budget
FROM tenders
WHERE sector = 'Solar';

SELECT * 
FROM bids 
WHERE bid_amount > 500000 AND status = 'Awarded';

SELECT COUNT(tender_id) 
FROM tenders 
WHERE sector = 'Solar';

SELECT DISTINCT company_name, sector 
FROM tenders 
WHERE strftime('%Y', date_posted) > '2021';

SELECT company_name, sector 
FROM tenders 
ORDER BY company_name ASC;

SELECT DISTINCT tender_id
FROM bids
ORDER BY bid_date DESC;

external_knowledge:
- "blossoming opportunities" metaphorically refers to open tenders;
- "solar garden of New York" represents tenders in the Solar sector located in New York;
- "seedlings" and "planting the seeds" metaphorically refer to documents and companies making bids;
- "gardeners" and their "identifiers" symbolize commenters and their user IDs, respectively;
- "full names" indicate the first and last names of gardeners.
